Here's a function I wrote for our billing schema — did I lock it down right?

```sql
create function billing.record_charge(p_account_id uuid, p_amount_cents integer)
returns uuid
language plpgsql
security definer
as $$
declare v_id uuid;
begin
  insert into billing.charges (account_id, amount_cents) values (p_account_id, p_amount_cents)
    returning id into v_id;
  return v_id;
end;
$$;

grant execute on function billing.record_charge(uuid, integer) to authenticated;
```
